import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import NeuralBackground from '../components/NeuralBackground';

export default function LoginPage() {
  const { signIn, signUp } = useAuth();
  const navigate = useNavigate();
  const [mode, setMode]       = useState('login'); // 'login' | 'signup'
  const [email, setEmail]     = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError]     = useState('');

  async function handleSubmit(e) {
    e.preventDefault();
    if (!email.trim() || !password)  { setError('Please enter your email and password.'); return; }
    if (mode === 'signup' && password.length < 6) { setError('Password must be at least 6 characters.'); return; }
    setLoading(true);
    setError('');
    try {
      if (mode === 'login') {
        await signIn(email.trim(), password);
      } else {
        await signUp(email.trim(), password);
      }
      navigate('/', { replace: true });
    } catch (err) {
      setError(err.message || 'Something went wrong. Please try again.');
    } finally {
      setLoading(false);
    }
  }

  return (
    <div style={{
      minHeight: '100vh', background: '#1a1a2e', display: 'flex',
      alignItems: 'center', justifyContent: 'center', padding: 24,
      position: 'relative', overflow: 'hidden',
    }}>
      <NeuralBackground />

      <div style={{
        position: 'relative', zIndex: 1, width: '100%', maxWidth: 400,
        background: '#252542', border: '1px solid #3d3d6b', borderRadius: 16,
        padding: '36px 32px', boxShadow: '0 8px 40px rgba(0,0,0,.4)',
      }}>
        {/* Logo */}
        <div style={{ textAlign: 'center', marginBottom: 28 }}>
          <div style={{ fontSize: 36, marginBottom: 10 }}>🧠</div>
          <div style={{ fontFamily: "'DM Mono', monospace", fontSize: 20, fontWeight: 500, color: '#f0f0ff', marginBottom: 6 }}>
            NeuroInsight
          </div>
          <div style={{ fontSize: 13, color: '#94a3b8' }}>
            fMRI & wearable mental wellbeing analysis
          </div>
        </div>

        {/* Mode toggle */}
        <div style={{
          display: 'flex', background: '#1a1a2e', borderRadius: 8,
          padding: 3, marginBottom: 24, gap: 3,
        }}>
          {['login', 'signup'].map(m => (
            <button
              key={m}
              type="button"
              onClick={() => { setMode(m); setError(''); }}
              style={{
                flex: 1, padding: '7px 0', borderRadius: 6, border: 'none',
                background: mode === m ? '#8b5cf6' : 'transparent',
                color: mode === m ? '#fff' : '#94a3b8',
                fontSize: 13, fontWeight: 500, cursor: 'pointer',
                transition: 'background .15s, color .15s',
              }}
            >
              {m === 'login' ? 'Sign in' : 'Create account'}
            </button>
          ))}
        </div>

        <form onSubmit={handleSubmit}>
          <div style={{ marginBottom: 14 }}>
            <label style={{ display: 'block', fontSize: 12, color: '#94a3b8', marginBottom: 6 }}>
              Email address
            </label>
            <input
              type="email"
              value={email}
              onChange={e => setEmail(e.target.value)}
              placeholder="you@example.com"
              autoFocus
              style={inputStyle}
              onFocus={e => e.target.style.borderColor = '#8b5cf6'}
              onBlur={e => e.target.style.borderColor = '#3d3d6b'}
            />
          </div>

          <div style={{ marginBottom: 20 }}>
            <label style={{ display: 'block', fontSize: 12, color: '#94a3b8', marginBottom: 6 }}>
              Password {mode === 'signup' && <span style={{ color: '#64748b' }}>(min 6 characters)</span>}
            </label>
            <input
              type="password"
              value={password}
              onChange={e => setPassword(e.target.value)}
              placeholder="••••••••"
              style={inputStyle}
              onFocus={e => e.target.style.borderColor = '#8b5cf6'}
              onBlur={e => e.target.style.borderColor = '#3d3d6b'}
            />
          </div>

          {error && (
            <div style={{
              padding: '10px 12px', borderRadius: 8, marginBottom: 16,
              background: 'rgba(248,81,73,.1)', border: '1px solid rgba(248,81,73,.3)',
              fontSize: 13, color: '#fca5a5',
            }}>
              {error}
            </div>
          )}

          <button
            type="submit"
            disabled={loading}
            style={{
              width: '100%', padding: '11px 0', borderRadius: 8, border: 'none',
              background: loading ? '#4c3880' : '#8b5cf6', color: '#fff',
              fontSize: 14, fontWeight: 600,
              cursor: loading ? 'not-allowed' : 'pointer',
              transition: 'background .15s',
            }}
          >
            {loading ? 'Please wait…' : mode === 'login' ? 'Sign in →' : 'Create account →'}
          </button>
        </form>

        <div style={{
          marginTop: 24, paddingTop: 18, borderTop: '1px solid #3d3d6b',
          fontSize: 11, color: '#64748b', textAlign: 'center', lineHeight: 1.5,
        }}>
          Research use only · Not a clinical diagnostic tool
        </div>
      </div>
    </div>
  );
}

const inputStyle = {
  width: '100%', padding: '10px 12px', borderRadius: 8,
  border: '1px solid #3d3d6b', background: '#1a1a2e',
  color: '#f0f0ff', fontSize: 14, outline: 'none',
  boxSizing: 'border-box', transition: 'border-color .15s',
};
